"""
task module - handles core task functionality
"""
from typing import Optional, List
from dataclasses import dataclass

@dataclass
class TaskService:
    id: int
    name: str
    status: str = "active"
    created_at: Optional[str] = None

    def validate(self) -> bool:
        """Validate the TaskService instance."""
        if not self.name:
            raise ValueError("Name is required")
        return True

    def to_dict(self) -> dict:
        """Convert to dictionary representation."""
        return {{
            "id": self.id,
            "name": self.name,
            "status": self.status,
            "created_at": self.created_at
        }}

import {{ Injectable }} from '@nestjs/common';
import {{ TaskService }} from './models/task.model';
import {{ TaskServiceRepository }} from './repositories/task.repository';

@Injectable()
export class TaskServiceService {{
  constructor(
    private readonly repository: TaskServiceRepository,
  ) {{}}

  async findAll(): Promise<TaskService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<TaskService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<TaskService>): Promise<TaskService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<TaskService>): Promise<TaskService> {{
    return this.repository.update(id, data);
  }}
}}
